from typing import List, Optional, Dict
from datetime import datetime
from models import Task

class TaskManager:
    def __init__(self, tasks: Optional[List[Task]] = None):
        self.tasks: List[Task] = tasks or []

    def create_task(self, title: str, description: str = "", priority: str = "medium") -> Task:
        task = Task(title=title, description=description, priority=priority)
        self.tasks.append(task)
        return task

    def list_tasks(self, status: Optional[str] = None, include_deleted: bool = False) -> List[Task]:
        filtered = self.tasks
        if not include_deleted:
            filtered = [t for t in filtered if not t.deleted]
        if status:
            filtered = [t for t in filtered if t.status == status]
        return filtered

    def complete_task(self, task_id: str) -> Optional[Task]:
        for task in self.tasks:
            if task.id == task_id:
                task.status = "completed"
                task.completed_at = datetime.now().isoformat()
                return task
        return None

    def delete_task(self, task_id: str, soft: bool = True) -> bool:
        for i, task in enumerate(self.tasks):
            if task.id == task_id:
                if soft:
                    task.deleted = True
                else:
                    self.tasks.pop(i)
                return True
        return False

    def get_stats(self) -> Dict:
        active_tasks = [t for t in self.tasks if not t.deleted]
        total = len(active_tasks)
        if total == 0:
            return {"total": 0, "pending": 0, "completed": 0, "completion_rate": 0.0}

        pending = sum(1 for t in active_tasks if t.status == "pending")
        completed = sum(1 for t in active_tasks if t.status == "completed")
        return {
            "total": total,
            "pending": pending,
            "completed": completed,
            "completion_rate": completed / total,
        }

    def search(self, query: str) -> List[Task]:
        query = query.lower()
        return [
            t for t in self.tasks 
            if not t.deleted and (query in t.title.lower() or query in t.description.lower())
        ]

    def sort_tasks(self, key: str = "created_at", reverse: bool = False) -> List[Task]:
        if key == "priority":
            return sorted(self.tasks, key=lambda t: t.priority_value, reverse=not reverse)
        return sorted(self.tasks, key=lambda t: getattr(t, key, ""), reverse=reverse)

